      "content": "const problemsData = require('../../data/problems.json');

function listProblems({ difficulty, limit = 50, includeComponents = false }) {
  // Filter by difficulty if provided
  let filtered = problemsData;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Sort by roundId ascending
  filtered.sort((a, b) => a.roundId - b.roundId);

  // Apply limit (max 50)
  const appliedLimit = Math.min(limit, 50);
  const limited = filtered.slice(0, appliedLimit);

  // Difficulty breakdown
  const difficultyBreakdown = filtered.reduce((acc, p) => {
    acc[p.difficulty] = (acc[p.difficulty] || 0) + 1;
    return acc;
  }, {});

  // Compose componentLanguages if includeComponents is true
  let componentLanguages = [];
  if (includeComponents) {
    const langsSet = new Set();
    limited.forEach(p => {
      if (p.componentLanguages && Array.isArray(p.componentLanguages)) {
        p.componentLanguages.forEach(lang => langsSet.add(lang));
      }
    });
    componentLanguages = Array.from(langsSet).sort();
  }

  return {
    totalProblems: problemsData.length,
    filteredCount: filtered.length,
    appliedLimit,
    difficultyBreakdown,
    problems: limited,
    componentLanguages
  };
}

module.exports = {
  listProblems
};
